// security/encryption.ts
import CryptoJS from 'crypto-js';
import * as Keychain from 'react-native-keychain';
import { Platform } from 'react-native';

class EncryptionService {
  private static instance: EncryptionService;
  private encryptionKey: string | null = null;

  static getInstance(): EncryptionService {
    if (!EncryptionService.instance) {
      EncryptionService.instance = new EncryptionService();
    }
    return EncryptionService.instance;
  }

  async initialize(): Promise<void> {
    try {
      const credentials = await Keychain.getGenericPassword({
        service: 'payment_encryption_key',
      });

      if (credentials) {
        this.encryptionKey = credentials.password;
      } else {
        this.encryptionKey = this.generateKey();
        await Keychain.setGenericPassword('payment_key', this.encryptionKey, {
          service: 'payment_encryption_key',
          accessControl: Keychain.ACCESS_CONTROL.BIOMETRY_CURRENT_SET_OR_DEVICE_PASSCODE,
          accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
        });
      }
    } catch (error) {
      console.error('Encryption initialization failed:', error);
      throw new Error('Failed to initialize encryption service');
    }
  }

  private generateKey(): string {
    const randomBytes = CryptoJS.lib.WordArray.random(32);
    return randomBytes.toString(CryptoJS.enc.Hex);
  }

  encrypt(data: string): string {
    if (!this.encryptionKey) {
      throw new Error('Encryption service not initialized');
    }
    const iv = CryptoJS.lib.WordArray.random(16);
    const encrypted = CryptoJS.AES.encrypt(data, CryptoJS.enc.Hex.parse(this.encryptionKey), {
      iv: iv,
      mode: CryptoJS.mode.CBC,
      padding: CryptoJS.pad.Pkcs7,
    });
    return iv.toString(CryptoJS.enc.Hex) + ':' + encrypted.toString();
  }

  decrypt(encryptedData: string): string {
    if (!this.encryptionKey) {
      throw new Error('Encryption service not initialized');
    }
    const parts = encryptedData.split(':');
    const iv = CryptoJS.enc.Hex.parse(parts[0]);
    const encrypted = parts[1];
    const decrypted = CryptoJS.AES.decrypt(encrypted, CryptoJS.enc.Hex.parse(this.encryptionKey), {
      iv: iv,
      mode: CryptoJS.mode.CBC,
      padding: CryptoJS.pad.Pkcs7,
    });
    return decrypted.toString(CryptoJS.enc.Utf8);
  }

  hashData(data: string): string {
    return CryptoJS.SHA256(data).toString(CryptoJS.enc.Hex);
  }

  generateTransactionSignature(transaction: Partial<Transaction>): string {
    const payload = JSON.stringify({
      id: transaction.id,
      amount: transaction.amount,
      currency: transaction.currency,
      timestamp: transaction.timestamp,
    });
    return CryptoJS.HmacSHA256(payload, this.encryptionKey || '').toString(CryptoJS.enc.Hex);
  }
}

export const encryptionService = EncryptionService.getInstance();

