// security/secureStorage.ts
import AsyncStorage from '@react-native-async-storage/async-storage';

class SecurePaymentStorage {
  private static instance: SecurePaymentStorage;

  static getInstance(): SecurePaymentStorage {
    if (!SecurePaymentStorage.instance) {
      SecurePaymentStorage.instance = new SecurePaymentStorage();
    }
    return SecurePaymentStorage.instance;
  }

  async storePaymentMethod(method: PaymentMethod): Promise<void> {
    try {
      const sanitized: PaymentMethod = {
        ...method,
        // Never store full card numbers
        last4: method.last4,
        tokenized: true,
      };
      const encrypted = encryptionService.encrypt(JSON.stringify(sanitized));
      const methods = await this.getPaymentMethods();
      methods.push(sanitized);
      await Keychain.setGenericPassword(
        'payment_methods',
        encryptionService.encrypt(JSON.stringify(methods)),
        {
          service: 'payment_methods_store',
          accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
        }
      );
    } catch (error) {
      console.error('Failed to store payment method:', error);
      throw error;
    }
  }

  async getPaymentMethods(): Promise<PaymentMethod[]> {
    try {
      const credentials = await Keychain.getGenericPassword({
        service: 'payment_methods_store',
      });
      if (credentials) {
        const decrypted = encryptionService.decrypt(credentials.password);
        return JSON.parse(decrypted);
      }
      return [];
    } catch {
      return [];
    }
  }

  async removePaymentMethod(methodId: string): Promise<void> {
    const methods = await this.getPaymentMethods();
    const filtered = methods.filter((m) => m.id !== methodId);
    await Keychain.setGenericPassword(
      'payment_methods',
      encryptionService.encrypt(JSON.stringify(filtered)),
      { service: 'payment_methods_store' }
    );
  }

  async storeTransactionHistory(transaction: Transaction): Promise<void> {
    try {
      const key = `txn_${transaction.id}`;
      const encrypted = encryptionService.encrypt(JSON.stringify(transaction));
      await AsyncStorage.setItem(key, encrypted);

      // Update transaction index
      const indexStr = await AsyncStorage.getItem('txn_index');
      const index: string[] = indexStr ? JSON.parse(indexStr) : [];
      index.unshift(transaction.id);
      // Keep last 100 transactions
      const trimmed = index.slice(0, 100);
      await AsyncStorage.setItem('txn_index', JSON.stringify(trimmed));
    } catch (error) {
      console.error('Failed to store transaction:', error);
    }
  }

  async getTransactionHistory(limit: number = 50): Promise<Transaction[]> {
    try {
      const indexStr = await AsyncStorage.getItem('txn_index');
      if (!indexStr) return [];

      const index: string[] = JSON.parse(indexStr);
      const transactions: Transaction[] = [];

      for (const txnId of index.slice(0, limit)) {
        const encrypted = await AsyncStorage.getItem(`txn_${txnId}`);
        if (encrypted) {
          const decrypted = encryptionService.decrypt(encrypted);
          transactions.push(JSON.parse(decrypted));
        }
      }
      return transactions;
    } catch {
      return [];
    }
  }

  async clearAllPaymentData(): Promise<void> {
    await Keychain.resetGenericPassword({ service: 'payment_methods_store' });
    const indexStr = await AsyncStorage.getItem('txn_index');
    if (indexStr) {
      const index: string[] = JSON.parse(indexStr);
      await Promise.all(index.map((id) => AsyncStorage.removeItem(`txn_${id}`)));
      await AsyncStorage.removeItem('txn_index');
    }
  }
}

export const secureStorage = SecurePaymentStorage.getInstance();

