// services/IAPService.ts
import {
  initConnection,
  endConnection,
  getProducts,
  getSubscriptions,
  requestPurchase,
  requestSubscription,
  finishTransaction,
  purchaseUpdatedListener,
  purchaseErrorListener,
  getAvailablePurchases,
  acknowledgePurchaseAndroid,
  type ProductPurchase,
  type SubscriptionPurchase,
  type PurchaseError as IAPPurchaseError,
} from 'react-native-iap';
import { Platform } from 'react-native';
import { v4 as uuidv4 } from 'uuid';

class IAPService {
  private static instance: IAPService;
  private purchaseUpdateSubscription: any = null;
  private purchaseErrorSubscription: any = null;
  private initialized: boolean = false;
  private purchaseCallbacks: Map<string, {
    resolve: (result: PaymentResult) => void;
    reject: (error: PaymentError) => void;
  }> = new Map();

  static getInstance(): IAPService {
    if (!IAPService.instance) {
      IAPService.instance = new IAPService();
    }
    return IAPService.instance;
  }

  async initialize(): Promise<void> {
    if (this.initialized) return;

    try {
      await initConnection();
      this.setupListeners();
      this.initialized = true;
      console.log('IAP Service initialized successfully');
    } catch (error) {
      console.error('IAP initialization failed:', error);
      throw error;
    }
  }

  private setupListeners(): void {
    this.purchaseUpdateSubscription = purchaseUpdatedListener(
      async (purchase: ProductPurchase | SubscriptionPurchase) => {
        console.log('Purchase update:', purchase.productId);

        try {
          // Validate receipt server-side
          const validationResult = await this.validateReceipt(purchase);

          if (validationResult.valid) {
            // Finish the transaction
            await finishTransaction({ purchase, isConsumable: true });

            // Acknowledge purchase on Android
            if (Platform.OS === 'android' && !purchase.isAcknowledgedAndroid) {
              await acknowledgePurchaseAndroid({ token: purchase.purchaseToken! });
            }

            const transaction: Transaction = {
              id: uuidv4(),
              productId: purchase.productId,
              provider: Platform.OS === 'ios' ? PaymentProvider.APPLE_IAP : PaymentProvider.GOOGLE_PLAY,
              status: TransactionStatus.COMPLETED,
              amount: 0, // Amount comes from product info
              currency: 'USD',
              receipt: Platform.OS === 'ios'
                ? purchase.transactionReceipt
                : purchase.purchaseToken,
              timestamp: Date.now(),
              userId: '', // Set from context
              metadata: {
                transactionId: purchase.transactionId,
                originalTransactionId: (purchase as any).originalTransactionIdentifierIOS,
              },
            };

            await secureStorage.storeTransactionHistory(transaction);

            // Resolve pending callback
            const callback = this.purchaseCallbacks.get(purchase.productId);
            if (callback) {
              callback.resolve({ success: true, transaction });
              this.purchaseCallbacks.delete(purchase.productId);
            }
          } else {
            throw new Error('Receipt validation failed');
          }
        } catch (error) {
          const paymentError: PaymentError = {
            code: 'PURCHASE_PROCESSING_FAILED',
            message: error instanceof Error ? error.message : 'Purchase processing failed',
            provider: Platform.OS === 'ios' ? PaymentProvider.APPLE_IAP : PaymentProvider.GOOGLE_PLAY,
            recoverable: true,
          };

          const callback = this.purchaseCallbacks.get(purchase.productId);
          if (callback) {
            callback.reject(paymentError);
            this.purchaseCallbacks.delete(purchase.productId);
          }
        }
      }
    );

    this.purchaseErrorSubscription = purchaseErrorListener(
      (error: IAPPurchaseError) => {
        console.error('Purchase error:', error);

        const paymentError: PaymentError = {
          code: error.code || 'PURCHASE_ERROR',
          message: error.message || 'An error occurred during purchase',
          provider: Platform.OS === 'ios' ? PaymentProvider.APPLE_IAP : PaymentProvider.GOOGLE_PLAY,
          recoverable: error.code !== 'E_USER_CANCELLED',
        };

        // Reject all pending callbacks
        this.purchaseCallbacks.forEach((callback) => {
          callback.reject(paymentError);
        });
        this.purchaseCallbacks.clear();
      }
    );
  }

  async getAvailableProducts(productIds: string[]): Promise<Product[]> {
    try {
      const platformIds = productIds.map((id) => id);
      const products = await getProducts({ skus: platformIds });

      return products.map((p) => ({
        id: p.productId,
        title: p.title,
        description: p.description,
        price: parseFloat(p.price),
        currency: p.currency,
        type: ProductType.CONSUMABLE,
        platformProductId: {
          [Platform.OS]: p.productId,
        },
      }));
    } catch (error) {
      console.error('Failed to fetch products:', error);
      return [];
    }
  }

  async getAvailableSubscriptions(subscriptionIds: string[]): Promise<Product[]> {
    try {
      const subscriptions = await getSubscriptions({ skus: subscriptionIds });

      return subscriptions.map((s) => ({
        id: s.productId,
        title: s.title,
        description: s.description,
        price: parseFloat(s.price),
        currency: s.currency,
        type: ProductType.SUBSCRIPTION,
        platformProductId: {
          [Platform.OS]: s.productId,
        },
      }));
    } catch (error) {
      console.error('Failed to fetch subscriptions:', error);
      return [];
    }
  }

  async purchaseProduct(product: Product): Promise<PaymentResult> {
    if (!this.initialized) {
      await this.initialize();
    }

    return new Promise<PaymentResult>((resolve, reject) => {
      this.purchaseCallbacks.set(product.id, { resolve, reject: (err) => resolve({ success: false, error: err }) });

      const platformId = Platform.OS === 'ios'
        ? product.platformProductId.ios
        : product.platformProductId.android;

      if (!platformId) {
        this.purchaseCallbacks.delete(product.id);
        resolve({
          success: false,
          error: {
            code: 'INVALID_PRODUCT',
            message: 'Product not available for this platform',
            recoverable: false,
          },
        });
        return;
      }

      requestPurchase({ sku: platformId }).catch((error) => {
        this.purchaseCallbacks.delete(product.id);
        resolve({
          success: false,
          error: {
            code: 'PURCHASE_REQUEST_FAILED',
            message: error.message,
            recoverable: true,
          },
        });
      });
    });
  }

  async purchaseSubscription(product: Product, offerToken?: string): Promise<PaymentResult> {
    if (!this.initialized) {
      await this.initialize();
    }

    return new Promise<PaymentResult>((resolve, reject) => {
      this.purchaseCallbacks.set(product.id, { resolve, reject: (err) => resolve({ success: false, error: err }) });

      const platformId = Platform.OS === 'ios'
        ? product.platformProductId.ios
        : product.platformProductId.android;

      if (!platformId) {
        this.purchaseCallbacks.delete(product.id);
        resolve({
          success: false,
          error: {
            code: 'INVALID_SUBSCRIPTION',
            message: 'Subscription not available for this platform',
            recoverable: false,
          },
        });
        return;
      }

      const subscriptionOffer = Platform.OS === 'android' && offerToken
        ? [{ sku: platformId, offerToken }]
        : undefined;

      requestSubscription({
        sku: platformId,
        ...(subscriptionOffer && { subscriptionOffers: subscriptionOffer }),
      }).catch((error) => {
        this.purchaseCallbacks.delete(product.id);
        resolve({
          success: false,
          error: {
            code: 'SUBSCRIPTION_REQUEST_FAILED',
            message: error.message,
            recoverable: true,
          },
        });
      });
    });
  }

  async restorePurchases(): Promise<Transaction[]> {
    try {
      const purchases = await getAvailablePurchases();
      const transactions: Transaction[] = purchases.map((p) => ({
        id: uuidv4(),
        productId: p.productId,
        provider: Platform.OS === 'ios' ? PaymentProvider.APPLE_IAP : PaymentProvider.GOOGLE_PLAY,
        status: TransactionStatus.COMPLETED,
        amount: 0,
        currency: 'USD',
        receipt: Platform.OS === 'ios' ? p.transactionReceipt : p.purchaseToken,
        timestamp: p.transactionDate,
        userId: '',
        metadata: { restored: true },
      }));

      for (const txn of transactions) {
        await secureStorage.storeTransactionHistory(txn);
      }

      return transactions;
    } catch (error) {
      console.error('Failed to restore purchases:', error);
      return [];
    }
  }

  private async validateReceipt(
    purchase: ProductPurchase | SubscriptionPurchase
  ): Promise<{ valid: boolean; data?: any }> {
    try {
      const response = await fetch('https://api.yourserver.com/validate-receipt', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${await this.getAuthToken()}`,
        },
        body: JSON.stringify({
          platform: Platform.OS,
          receipt: Platform.OS === 'ios'
            ? purchase.transactionReceipt
            : purchase.purchaseToken,
          productId: purchase.productId,
          packageName: Platform.OS === 'android' ? 'com.yourapp.package' : undefined,
        }),
      });

      const result = await response.json();
      return { valid: result.valid, data: result };
    } catch (error) {
      console.error('Receipt validation error:', error);
      // In production, you might want to fail closed (return false)
      // For development, we return true with a warning
      console.warn('WARNING: Receipt validation skipped due to network error');
      return { valid: false };
    }
  }

  private async getAuthToken(): Promise<string> {
    // Retrieve auth token from secure storage
    const credentials = await Keychain.getGenericPassword({ service: 'auth_token' });
    return credentials ? credentials.password : '';
  }

  async cleanup(): Promise<void> {
    if (this.purchaseUpdateSubscription) {
      this.purchaseUpdateSubscription.remove();
    }
    if (this.purchaseErrorSubscription) {
      this.purchaseErrorSubscription.remove();
    }
    await endConnection();
    this.initialized = false;
  }
}

export const iapService = IAPService.getInstance();

