// services/WalletService.ts
import { Platform, NativeModules } from 'react-native';

interface WalletPaymentRequest {
  amount: number;
  currency: string;
  merchantName: string;
  merchantId: string;
  countryCode: string;
  description: string;
}

class DigitalWalletService {
  private static instance: DigitalWalletService;
  private stripePublishableKey: string = '';

  static getInstance(): DigitalWalletService {
    if (!DigitalWalletService.instance) {
      DigitalWalletService.instance = new DigitalWalletService();
    }
    return DigitalWalletService.instance;
  }

  async initialize(config: {
    stripePublishableKey: string;
    merchantId: string;
  }): Promise<void> {
    this.stripePublishableKey = config.stripePublishableKey;

    // Initialize Stripe
    try {
      const { initStripe } = require('@stripe/stripe-react-native');
      await initStripe({
        publishableKey: config.stripePublishableKey,
        merchantIdentifier: config.merchantId,
        urlScheme: 'yourapp',
      });
    } catch (error) {
      console.error('Stripe initialization failed:', error);
    }
  }

  async isWalletAvailable(walletType: WalletType): Promise<boolean> {
    try {
      const { isApplePaySupported, isGooglePaySupported } = require('@stripe/stripe-react-native');

      switch (walletType) {
        case WalletType.APPLE_PAY:
          if (Platform.OS !== 'ios') return false;
          return await isApplePaySupported();

        case WalletType.GOOGLE_PAY:
          if (Platform.OS !== 'android') return false;
          return await isGooglePaySupported({
            testEnv: __DEV__,
            existingPaymentMethodRequired: false,
          });

        default:
          return false;
      }
    } catch {
      return false;
    }
  }

  async getAvailableWallets(): Promise<WalletType[]> {
    const available: WalletType[] = [];

    const wallets = Platform.OS === 'ios'
      ? [WalletType.APPLE_PAY]
      : [WalletType.GOOGLE_PAY, WalletType.SAMSUNG_PAY];

    for (const wallet of wallets) {
      if (await this.isWalletAvailable(wallet)) {
        available.push(wallet);
      }
    }

    return available;
  }

  async payWithApplePay(request: WalletPaymentRequest): Promise<PaymentResult> {
    try {
      const {
        presentApplePay,
        confirmApplePayPayment,
      } = require('@stripe/stripe-react-native');

      const { error: presentError } = await presentApplePay({
        cartItems: [
          {
            label: request.description,
            amount: request.amount.toFixed(2),
            paymentType: 'Immediate',
          },
        ],
        country: request.countryCode,
        currency: request.currency,
      });

      if (presentError) {
        return {
          success: false,
          error: {
            code: presentError.code,
            message: presentError.message,
            provider: PaymentProvider.DIGITAL_WALLET,
            recoverable: presentError.code === 'Canceled',
          },
        };
      }

      // Create payment intent on server
      const paymentIntent = await this.createPaymentIntent({
        amount: Math.round(request.amount * 100),
        currency: request.currency,
        paymentMethod: 'apple_pay',
      });

      const { error: confirmError } = await confirmApplePayPayment(
        paymentIntent.clientSecret
      );

      if (confirmError) {
        return {
          success: false,
          error: {
            code: confirmError.code,
            message: confirmError.message,
            provider: PaymentProvider.DIGITAL_WALLET,
            recoverable: true,
          },
        };
      }

      const transaction: Transaction = {
        id: uuidv4(),
        productId: 'wallet_payment',
        provider: PaymentProvider.DIGITAL_WALLET,
        status: TransactionStatus.COMPLETED,
        amount: request.amount,
        currency: request.currency,
        receipt: paymentIntent.id,
        timestamp: Date.now(),
        userId: '',
        metadata: {
          walletType: WalletType.APPLE_PAY,
          paymentIntentId: paymentIntent.id,
        },
      };

      await secureStorage.storeTransactionHistory(transaction);

      return { success: true, transaction };
    } catch (error) {
      return {
        success: false,
        error: {
          code: 'APPLE_PAY_ERROR',
          message: error instanceof Error ? error.message : 'Apple Pay failed',
          provider: PaymentProvider.DIGITAL_WALLET,
          recoverable: true,
        },
      };
    }
  }

  async payWithGooglePay(request: WalletPaymentRequest): Promise<PaymentResult> {
    try {
      const {
        initGooglePay,
        presentGooglePay,
      } = require('@stripe/stripe-react-native');

      const { error: initError } = await initGooglePay({
        testEnv: __DEV__,
        merchantName: request.merchantName,
        countryCode: request.countryCode,
        billingAddressConfig: {
          format: 'FULL',
          isPhoneNumberRequired: false,
          isRequired: false,
        },
        existingPaymentMethodRequired: false,
        isEmailRequired: false,
      });

      if (initError) {
        return {
          success: false,
          error: {
            code: initError.code,
            message: initError.message,
            provider: PaymentProvider.DIGITAL_WALLET,
            recoverable: true,
          },
        };
      }

      // Create payment intent on server
      const paymentIntent = await this.createPaymentIntent({
        amount: Math.round(request.amount * 100),
        currency: request.currency,
        paymentMethod: 'google_pay',
      });

      const { error: presentError } = await presentGooglePay({
        clientSecret: paymentIntent.clientSecret,
        forSetupIntent: false,
      });

      if (presentError) {
        return {
          success: false,
          error: {
            code: presentError.code,
            message: presentError.message,
            provider: PaymentProvider.DIGITAL_WALLET,
            recoverable: presentError.code === 'Canceled',
          },
        };
      }

      const transaction: Transaction = {
        id: uuidv4(),
        productId: 'wallet_payment',
        provider: PaymentProvider.DIGITAL_WALLET,
        status: TransactionStatus.COMPLETED,
        amount: request.amount,
        currency: request.currency,
        receipt: paymentIntent.id,
        timestamp: Date.now(),
        userId: '',
        metadata: {
          walletType: WalletType.GOOGLE_PAY,
          paymentIntentId: paymentIntent.id,
        },
      };

      await secureStorage.storeTransactionHistory(transaction);

      return { success: true, transaction };
    } catch (error) {
      return {
        success: false,
        error: {
          code: 'GOOGLE_PAY_ERROR',
          message: error instanceof Error ? error.message : 'Google Pay failed',
          provider: PaymentProvider.DIGITAL_WALLET,
          recoverable: true,
        },
      };
    }
  }

  async payWithCard(params: {
    amount: number;
    currency: string;
    paymentMethodId: string;
  }): Promise<PaymentResult> {
    try {
      const { confirmPayment } = require('@stripe/stripe-react-native');

      const paymentIntent = await this.createPaymentIntent({
        amount: Math.round(params.amount * 100),
        currency: params.currency,
        paymentMethod: 'card',
      });

      const { error, paymentIntent: confirmedIntent } = await confirmPayment(
        paymentIntent.clientSecret,
        {
          paymentMethodType: 'Card',
          paymentMethodData: {
            paymentMethodId: params.paymentMethodId,
          },
        }
      );

      if (error) {
        return {
          success: false,
          error: {
            code: error.code,
            message: error.message,
            provider: PaymentProvider.STRIPE,
            recoverable: true,
          },
        };
      }

      const transaction: Transaction = {
        id: uuidv4(),
        productId: 'card_payment',
        provider: PaymentProvider.STRIPE,
        status: TransactionStatus.COMPLETED,
        amount: params.amount,
        currency: params.currency,
        receipt: confirmedIntent?.id,
        timestamp: Date.now(),
        userId: '',
        metadata: {
          stripePaymentIntentId: confirmedIntent?.id,
        },
      };

      await secureStorage.storeTransactionHistory(transaction);

      return { success: true, transaction };
    } catch (error) {
      return {
        success: false,
        error: {
          code: 'CARD_PAYMENT_ERROR',
          message: error instanceof Error ? error.message : 'Card payment failed',
          provider: PaymentProvider.STRIPE,
          recoverable: true,
        },
      };
    }
  }

  private async createPaymentIntent(params: {
    amount: number;
    currency: string;
    paymentMethod: string;
  }): Promise<{ clientSecret: string; id: string }> {
    const response = await fetch('https://api.yourserver.com/create-payment-intent', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${await this.getAuthToken()}`,
      },
      body: JSON.stringify(params),
    });

    if (!response.ok) {
      throw new Error('Failed to create payment intent');
    }

    return response.json();
  }

  private async getAuthToken(): Promise<string> {
    const credentials = await Keychain.getGenericPassword({ service: 'auth_token' });
    return credentials ? credentials.password : '';
  }
}

export const walletService = DigitalWalletService.getInstance();

