// context/PaymentContext.tsx
import React, { createContext, useContext, useReducer, useEffect, useCallback, useRef } from 'react';
import { AppState, AppStateStatus } from 'react-native';

interface PaymentState {
  initialized: boolean;
  loading: boolean;
  products: Product[];
  subscriptions: Product[];
  paymentMethods: PaymentMethod[];
  availableWallets: WalletType[];
  transactions: Transaction[];
  activeSubscriptions: SubscriptionInfo[];
  error: PaymentError | null;
  processingPayment: boolean;
}

type PaymentAction =
  | { type: 'SET_INITIALIZED'; payload: boolean }
  | { type: 'SET_LOADING'; payload: boolean }
  | { type: 'SET_PRODUCTS'; payload: Product[] }
  | { type: 'SET_SUBSCRIPTIONS'; payload: Product[] }
  | { type: 'SET_PAYMENT_METHODS'; payload: PaymentMethod[] }
  | { type: 'SET_AVAILABLE_WALLETS'; payload: WalletType[] }
  | { type: 'SET_TRANSACTIONS'; payload: Transaction[] }
  | { type: 'ADD_TRANSACTION'; payload: Transaction }
  | { type: 'SET_ACTIVE_SUBSCRIPTIONS'; payload: SubscriptionInfo[] }
  | { type: 'SET_ERROR'; payload: PaymentError | null }
  | { type: 'SET_PROCESSING'; payload: boolean }
  | { type: 'REMOVE_PAYMENT_METHOD'; payload: string };

interface PaymentContextType {
  state: PaymentState;
  purchaseProduct: (product: Product) => Promise<PaymentResult>;
  purchaseSubscription: (product: Product) => Promise<PaymentResult>;
  payWithWallet: (walletType: WalletType, amount: number, currency: string, description: string) => Promise<PaymentResult>;
  payWithCard: (amount: number, currency: string, paymentMethodId: string) => Promise<PaymentResult>;
  restorePurchases: () => Promise<void>;
  addPaymentMethod: (method: PaymentMethod) => Promise<void>;
  removePaymentMethod: (methodId: string) => Promise<void>;
  refreshProducts: (productIds: string[], subscriptionIds: string[]) => Promise<void>;
  clearError: () => void;
}

const initialState: PaymentState = {
  initialized: false,
  loading: false,
  products: [],
  subscriptions: [],
  paymentMethods: [],
  availableWallets: [],
  transactions: [],
  activeSubscriptions: [],
  error: null,
  processingPayment: false,
};

function paymentReducer(state: PaymentState, action: PaymentAction): PaymentState {
  switch (action.type) {
    case 'SET_INITIALIZED':
      return { ...state, initialized: action.payload };
    case 'SET_LOADING':
      return { ...state, loading: action.payload };
    case 'SET_PRODUCTS':
      return { ...state, products: action.payload };
    case 'SET_SUBSCRIPTIONS':
      return { ...state, subscriptions: action.payload };
    case 'SET_PAYMENT_METHODS':
      return { ...state, paymentMethods: action.payload };
    case 'SET_AVAILABLE_WALLETS':
      return { ...state, availableWallets: action.payload };
    case 'SET_TRANSACTIONS':
      return { ...state, transactions: action.payload };
    case 'ADD_TRANSACTION':
      return { ...state, transactions: [action.payload, ...state.transactions] };
    case 'SET_ACTIVE_SUBSCRIPTIONS':
      return { ...state, activeSubscriptions: action.payload };
    case 'SET_ERROR':
      return { ...state, error: action.payload };
    case 'SET_PROCESSING':
      return { ...state, processingPayment: action.payload };
    case 'REMOVE_PAYMENT_METHOD':
      return {
        ...state,
        paymentMethods: state.paymentMethods.filter((m) => m.id !== action.payload),
      };
    default:
      return state;
  }
}

const PaymentContext = createContext<PaymentContextType | undefined>(undefined);

export const PaymentProvider: React.FC<{
  children: React.ReactNode;
  config: {
    stripePublishableKey: string;
    merchantId: string;
    merchantName: string;
    countryCode: string;
    productIds: string[];
    subscriptionIds: string[];
  };
}> = ({ children, config }) => {
  const [state, dispatch] = useReducer(paymentReducer, initialState);
  const appStateRef = useRef(AppState.currentState);

  useEffect(() => {
    initializePaymentServices();

    const subscription = AppState.addEventListener('change', handleAppStateChange);

    return () => {
      subscription.remove();
      iapService.cleanup();
    };
  }, []);

  const handleAppStateChange = useCallback(async (nextAppState: AppStateStatus) => {
    if (appStateRef.current.match(/inactive|background/) && nextAppState === 'active') {
      // Refresh data when app comes to foreground
      const transactions = await secureStorage.getTransactionHistory();
      dispatch({ type: 'SET_TRANSACTIONS', payload: transactions });
    }
    appStateRef.current = nextAppState;
  }, []);

  const initializePaymentServices = async () => {
    dispatch({ type: 'SET_LOADING', payload: true });

    try {
      // Initialize encryption
      await encryptionService.initialize();

      // Initialize IAP
      await iapService.initialize();

      // Initialize wallet service
      await walletService.initialize({
        stripePublishableKey: config.stripePublishableKey,
        merchantId: config.merchantId,
      });

      // Load products
      const products = await iapService.getAvailableProducts(config.productIds);
      dispatch({ type: 'SET_PRODUCTS', payload: products });

      // Load subscriptions
      const subscriptions = await iapService.getAvailableSubscriptions(config.subscriptionIds);
      dispatch({ type: 'SET_SUBSCRIPTIONS', payload: subscriptions });

      // Load available wallets
      const wallets = await walletService.getAvailableWallets();
      dispatch({ type: 'SET_AVAILABLE_WALLETS', payload: wallets });

      // Load payment methods
      const methods = await secureStorage.getPaymentMethods();
      dispatch({ type: 'SET_PAYMENT_METHODS', payload: methods });

      // Load transaction history
      const transactions = await secureStorage.getTransactionHistory();
      dispatch({ type: 'SET_TRANSACTIONS', payload: transactions });

      dispatch({ type: 'SET_INITIALIZED', payload: true });
    } catch (error) {
      dispatch({
        type: 'SET_ERROR',
        payload: {
          code: 'INIT_FAILED',
          message: 'Failed to initialize payment services',
          recoverable: true,
        },
      });
    } finally {
      dispatch({ type: 'SET_LOADING', payload: false });
    }
  };

  const purchaseProduct = useCallback(async (product: Product): Promise<PaymentResult> => {
    dispatch({ type: 'SET_PROCESSING', payload: true });
    dispatch({ type: 'SET_ERROR', payload: null });

    try {
      const result = await iapService.purchaseProduct(product);
      if (result.success && result.transaction) {
        dispatch({ type: 'ADD_TRANSACTION', payload: result.transaction });
      } else if (result.error) {
        dispatch({ type: 'SET_ERROR', payload: result.error });
      }
      return result;
    } catch (error) {
      const paymentError: PaymentError = {
        code: 'PURCHASE_FAILED',
        message: error instanceof Error ? error.message : 'Purchase failed',
        recoverable: true,
      };
      dispatch({ type: 'SET_ERROR', payload: paymentError });
      return { success: false, error: paymentError };
    } finally {
      dispatch({ type: 'SET_PROCESSING', payload: false });
    }
  }, []);

  const purchaseSubscription = useCallback(async (product: Product): Promise<PaymentResult> => {
    dispatch({ type: 'SET_PROCESSING', payload: true });
    dispatch({ type: 'SET_ERROR', payload: null });

    try {
      const result = await iapService.purchaseSubscription(product);
      if (result.success && result.transaction) {
        dispatch({ type: 'ADD_TRANSACTION', payload: result.transaction });
      } else if (result.error) {
        dispatch({ type: 'SET_ERROR', payload: result.error });
      }
      return result;
    } catch (error) {
      const paymentError: PaymentError = {
        code: 'SUBSCRIPTION_FAILED',
        message: error instanceof Error ? error.message : 'Subscription failed',
        recoverable: true,
      };
      dispatch({ type: 'SET_ERROR', payload: paymentError });
      return { success: false, error: paymentError };
    } finally {
      dispatch({ type: 'SET_PROCESSING', payload: false });
    }
  }, []);

  const payWithWallet = useCallback(async (
    walletType: WalletType,
    amount: number,
    currency: string,
    description: string
  ): Promise<PaymentResult> => {
    dispatch({ type: 'SET_PROCESSING', payload: true });
    dispatch({ type: 'SET_ERROR', payload: null });

    try {
      const request = {
        amount,
        currency,
        merchantName: config.merchantName,
        merchantId: config.merchantId,
        countryCode: config.countryCode,
        description,
      };

      let result: PaymentResult;

      switch (walletType) {
        case WalletType.APPLE_PAY:
          result = await walletService.payWithApplePay(request);
          break;
        case WalletType.GOOGLE_PAY:
          result = await walletService.payWithGooglePay(request);
          break;
        default:
          result = {
            success: false,
            error: {
              code: 'UNSUPPORTED_WALLET',
              message: `Wallet type ${walletType} is not supported`,
              recoverable: false,
            },
          };
      }

      if (result.success && result.transaction) {
        dispatch({ type: 'ADD_TRANSACTION', payload: result.transaction });
      } else if (result.error) {
        dispatch({ type: 'SET_ERROR', payload: result.error });
      }

      return result;
    } catch (error) {
      const paymentError: PaymentError = {
        code: 'WALLET_PAYMENT_FAILED',
        message: error instanceof Error ? error.message : 'Wallet payment failed',
        recoverable: true,
      };
      dispatch({ type: 'SET_ERROR', payload: paymentError });
      return { success: false, error: paymentError };
    } finally {
      dispatch({ type: 'SET_PROCESSING', payload: false });
    }
  }, [config]);

  const payWithCard = useCallback(async (
    amount: number,
    currency: string,
    paymentMethodId: string
  ): Promise<PaymentResult> => {
    dispatch({ type: 'SET_PROCESSING', payload: true });
    dispatch({ type: 'SET_ERROR', payload: null });

    try {
      const result = await walletService.payWithCard({
        amount,
        currency,
        paymentMethodId,
      });

      if (result.success && result.transaction) {
        dispatch({ type: 'ADD_TRANSACTION', payload: result.transaction });
      } else if (result.error) {
        dispatch({ type: 'SET_ERROR', payload: result.error });
      }

      return result;
    } catch (error) {
      const paymentError: PaymentError = {
        code: 'CARD_PAYMENT_FAILED',
        message: error instanceof Error ? error.message : 'Card payment failed',
        recoverable: true,
      };
      dispatch({ type: 'SET_ERROR', payload: paymentError });
      return { success: false, error: paymentError };
    } finally {
      dispatch({ type: 'SET_PROCESSING', payload: false });
    }
  }, []);

  const restorePurchases = useCallback(async () => {
    dispatch({ type: 'SET_LOADING', payload: true });
    try {
      const restoredTransactions = await iapService.restorePurchases();
      const allTransactions = await secureStorage.getTransactionHistory();
      dispatch({ type: 'SET_TRANSACTIONS', payload: allTransactions });
    } catch (error) {
      dispatch({
        type: 'SET_ERROR',
        payload: {
          code: 'RESTORE_FAILED',
          message: 'Failed to restore purchases',
          recoverable: true,
        },
      });
    } finally {
      dispatch({ type: 'SET_LOADING', payload: false });
    }
  }, []);

  const addPaymentMethod = useCallback(async (method: PaymentMethod) => {
    await secureStorage.storePaymentMethod(method);
    const methods = await secureStorage.getPaymentMethods();
    dispatch({ type: 'SET_PAYMENT_METHODS', payload: methods });
  }, []);

  const removePaymentMethod = useCallback(async (methodId: string) => {
    await secureStorage.removePaymentMethod(methodId);
    dispatch({ type: 'REMOVE_PAYMENT_METHOD', payload: methodId });
  }, []);

  const refreshProducts = useCallback(async (productIds: string[], subscriptionIds: string[]) => {
    dispatch({ type: 'SET_LOADING', payload: true });
    try {
      const products = await iapService.getAvailableProducts(productIds);
      dispatch({ type: 'SET_PRODUCTS', payload: products });
      const subscriptions = await iapService.getAvailableSubscriptions(subscriptionIds);
      dispatch({ type: 'SET_SUBSCRIPTIONS', payload: subscriptions });
    } finally {
      dispatch({ type: 'SET_LOADING', payload: false });
    }
  }, []);

  const clearError = useCallback(() => {
    dispatch({ type: 'SET_ERROR', payload: null });
  }, []);

  const contextValue: PaymentContextType = {
    state,
    purchaseProduct,
    purchaseSubscription,
    payWithWallet,
    payWithCard,
    restorePurchases,
    addPaymentMethod,
    removePaymentMethod,
    refreshProducts,
    clearError,
  };

  return (
    <PaymentContext.Provider value={contextValue}>
      {children}
    </PaymentContext.Provider>
  );
};

export const usePayment = (): PaymentContextType => {
  const context = useContext(PaymentContext);
  if (!context) {
    throw new Error('usePayment must be used within a PaymentProvider');
  }
  return context;
};

