// screens/PaymentScreen.tsx
import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  ScrollView,
  RefreshControl,
  Alert,
  Modal,
  TouchableOpacity,
  ActivityIndicator,
  SafeAreaView,
  FlatList,
} from 'react-native';

export const PaymentScreen: React.FC = () => {
  const {
    state,
    purchaseProduct,
    purchaseSubscription,
    payWithWallet,
    restorePurchases,
    removePaymentMethod,
    clearError,
  } = usePayment();

  const [refreshing, setRefreshing] = useState(false);
  const [selectedTab, setSelectedTab] = useState<'products' | 'subscriptions' | 'history'>('products');
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);

  useEffect(() => {
    if (state.error) {
      Alert.alert(
        'Payment Error',
        state.error.message,
        [
          {
            text: 'OK',
            onPress: clearError,
          },
          ...(state.error.recoverable
            ? [
                {
                  text: 'Retry',
                  onPress: () => {
                    clearError();
                    if (selectedProduct) {
                      handlePurchase(selectedProduct);
                    }
                  },
                },
              ]
            : []),
        ]
      );
    }
  }, [state.error]);

  const onRefresh = async () => {
    setRefreshing(true);
    await restorePurchases();
    setRefreshing(false);
  };

  const handlePurchase = async (product: Product) => {
    setSelectedProduct(product);

    if (product.type === ProductType.SUBSCRIPTION) {
      Alert.alert(
        'Subscribe',
        `Subscribe to ${product.title} for ${product.currency} ${product.price.toFixed(2)}/month?`,
        [
          { text: 'Cancel', style: 'cancel' },
          {
            text: 'Subscribe',
            onPress: async () => {
              const result = await purchaseSubscription(product);
              if (result.success) {
                Alert.alert('Success', 'Subscription activated successfully!');
              }
            },
          },
        ]
      );
    } else {
      setShowPaymentModal(true);
    }
  };

  const handleWalletPay = async (walletType: WalletType) => {
    if (!selectedProduct) return;
    setShowPaymentModal(false);

    const result = await payWithWallet(
      walletType,
      selectedProduct.price,
      selectedProduct.currency,
      selectedProduct.title
    );

    if (result.success) {
      Alert.alert('Success', 'Payment completed successfully!');
    }
  };

  const handleIAPPurchase = async () => {
    if (!selectedProduct) return;
    setShowPaymentModal(false);

    const result = await purchaseProduct(selectedProduct);
    if (result.success) {
      Alert.alert('Success', 'Purchase completed successfully!');
    }
  };

  const renderPaymentModal = () => (
    <Modal
      visible={showPaymentModal}
      animationType="slide"
      presentationStyle="pageSheet"
      onRequestClose={() => setShowPaymentModal(false)}
    >
      <SafeAreaView style={styles.modalContainer}>
        <View style={styles.modalHeader}>
          <Text style={styles.modalTitle}>Choose Payment Method</Text>
          <TouchableOpacity onPress={() => setShowPaymentModal(false)}>
            <Text style={styles.closeButton}>✕</Text>
          </TouchableOpacity>
        </View>

        {selectedProduct && (
          <View style={styles.modalProductInfo}>
            <Text style={styles.modalProductTitle}>{selectedProduct.title}</Text>
            <Text style={styles.modalProductPrice}>
              {selectedProduct.currency} {selectedProduct.price.toFixed(2)}
            </Text>
          </View>
        )}

        <View style={styles.paymentOptions}>
          {/* In-App Purchase */}
          <TouchableOpacity
            style={styles.paymentOption}
            onPress={handleIAPPurchase}
            disabled={state.processingPayment}
          >
            <Text style={styles.paymentOptionIcon}>🏪</Text>
            <Text style={styles.paymentOptionText}>
              {Platform.OS === 'ios' ? 'Apple App Store' : 'Google Play'}
            </Text>
          </TouchableOpacity>

          {/* Digital Wallets */}
          {state.availableWallets.map((wallet) => (
            <WalletPayButton
              key={wallet}
              walletType={wallet}
              amount={selectedProduct?.price || 0}
              currency={selectedProduct?.currency || 'USD'}
              description={selectedProduct?.title || ''}
              onPress={() => handleWalletPay(wallet)}
              disabled={state.processingPayment}
            />
          ))}

          {/* Saved Payment Methods */}
          {state.paymentMethods.map((method) => (
            <TouchableOpacity
              key={method.id}
              style={styles.paymentOption}
              disabled={state.processingPayment}
            >
              <Text style={styles.paymentOptionIcon}>💳</Text>
              <Text style={styles.paymentOptionText}>
                {method.brand} •••• {method.last4}
              </Text>
            </TouchableOpacity>
          ))}
        </View>

        {state.processingPayment && (
          <View style={styles.processingOverlay}>
            <ActivityIndicator size="large" color="#007AFF" />
            <Text style={styles.processingText}>Processing payment...</Text>
          </View>
        )}
      </SafeAreaView>
    </Modal>
  );

  const renderTabs = () => (
    <View style={styles.tabContainer}>
      {(['products', 'subscriptions', 'history'] as const).map((tab) => (
        <TouchableOpacity
          key={tab}
          style={[styles.tab, selectedTab === tab && styles.activeTab]}
          onPress={() => setSelectedTab(tab)}
        >
          <Text style={[styles.tabText, selectedTab === tab && styles.activeTabText]}>
            {tab.charAt(0).toUpperCase() + tab.slice(1)}
          </Text>
        </TouchableOpacity>
      ))}
    </View>
  );

  if (!state.initialized) {
    return (
      <View style={styles.centerContainer}>
        <ActivityIndicator size="large" color="#007AFF" />
        <Text style={styles.loadingText}>Initializing payment services...</Text>
      </View>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      {renderTabs()}

      <ScrollView
        refreshControl={<RefreshControl refreshing={refreshing} onRefresh={onRefresh} />}
        contentContainerStyle={styles.scrollContent}
      >
        {selectedTab === 'products' && (
          <View>
            <Text style={styles.sectionTitle}>Available Products</Text>
            {state.products.length === 0 ? (
              <Text style={styles.emptyText}>No products available</Text>
            ) : (
              state.products.map((product) => (
                <ProductCard
                  key={product.id}
                  product={product}
                  onPurchase={handlePurchase}
                  processing={state.processingPayment}
                />
              ))
            )}
          </View>
        )}

        {selectedTab === 'subscriptions' && (
          <View>
            <Text style={styles.sectionTitle}>Subscriptions</Text>
            {state.subscriptions.length === 0 ? (
              <Text style={styles.emptyText}>No subscriptions available</Text>
            ) : (
              state.subscriptions.map((sub) => (
                <ProductCard
                  key={sub.id}
                  product={sub}
                  onPurchase={handlePurchase}
                  processing={state.processingPayment}
                />
              ))
            )}

            <TouchableOpacity style={styles.restoreButton} onPress={restorePurchases}>
              <Text style={styles.restoreButtonText}>Restore Purchases</Text>
            </TouchableOpacity>
          </View>
        )}

        {selectedTab === 'history' && (
          <View>
            <Text style={styles.sectionTitle}>Transaction History</Text>
            {state.transactions.length === 0 ? (
              <Text style={styles.emptyText}>No transactions yet</Text>
            ) : (
              state.transactions.map((txn) => (
                <TransactionItem key={txn.id} transaction={txn} />
              ))
            )}
          </View>
        )}
      </ScrollView>

      {renderPaymentModal()}
    </SafeAreaView>
  );
};

